//! Snapshot tests for contract schema validation and fallback.\n//!\n//! Each contract module is tested against:\n//! - Valid payload decoding (`decode_and_validate`)\n//! - Empty completion handling\n//! - Invalid JSON handling\n//! - Field-level validation (missing required fields)\n//! - Fallback construction\n//! - Schema version constants\n\nuse klass_gateway::contracts::content_draft;\nuse klass_gateway::contracts::delivery;\nuse klass_gateway::contracts::prompt_interpretation;\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 1. Prompt Interpretation Schema\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_interpretation_schema_version() {\n    assert_eq!(\n        prompt_interpretation::SCHEMA_VERSION,\n        \"media_prompt_understanding.v1\"\n    );\n}\n\n#[test]\nfn test_interpretation_decode_valid() {\n    let json = r#"{\n        \"schema_version\": \"media_prompt_understanding.v1\",\n        \"teacher_prompt\": \"Buatkan materi pecahan untuk kelas 5 SD\",\n        \"language\": \"id\",\n        \"teacher_intent\": {\n            \"type\": \"generate_learning_media\",\n            \"goal\": \"Membuat materi pecahan\",\n            \"preferred_delivery_mode\": \"digital_download\",\n            \"requires_clarification\": false\n        },\n        \"learning_objectives\": [\"Memahami konsep pecahan\"],\n        \"constraints\": {\n            \"preferred_output_type\": \"pdf\"\n        },\n        \"output_type_candidates\": [\n            {\"type\": \"pdf\", \"score\": 0.9, \"reason\": \"Best for printout\"}\n        ],\n        \"resolved_output_type_reasoning\": \"PDF is best choice\",\n        \"document_blueprint\": {\n            \"title\": \"Materi Pecahan\",\n            \"summary\": \"Pengenalan pecahan untuk siswa kelas 5\",\n            \"sections\": [\n                {\n                    \"title\": \"Pengertian\",\n                    \"purpose\": \"Perkenalan konsep\",\n                    \"bullets\": [\"Definisi pecahan\"],\n                    \"estimated_length\": \"short\"\n                }\n            ]\n        },\n        \"teacher_delivery_summary\": \"Panduan mengajar materi pecahan\",\n        \"confidence\": {\n            \"score\": 0.85,\n            \"label\": \"high\"\n        }\n    }\"#;\n    let result = prompt_interpretation::decode_and_validate(json);\n    assert!(result.is_ok(), \"should decode valid payload: {:?}\", result.err());\n\n    let payload = result.unwrap();\n    assert_eq!(payload.language, \"id\");\n    assert_eq!(payload.output_type_candidates.len(), 1);\n    assert_eq!(payload.output_type_candidates[0].r#type, \"pdf\");\n    assert_eq!(payload.document_blueprint.sections.len(), 1);\n    assert!(!payload.fallback.triggered);\n}\n\n#[test]\nfn test_interpretation_decode_empty_returns_error() {\n    let result = prompt_interpretation::decode_and_validate(\"\");\n    assert!(result.is_err());\n    assert_eq!(result.unwrap_err().code, \"empty_completion\");\n}\n\n#[test]\nfn test_interpretation_decode_whitespace_returns_error() {\n    let result = prompt_interpretation::decode_and_validate(\"   \");\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_interpretation_decode_invalid_json() {\n    let result = prompt_interpretation::decode_and_validate(\"{invalid json}\");\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_interpretation_decode_missing_required_field() {\n    // Missing teacher_intent.goal (required field with garde validation)\n    let json = r#"{\n        \"schema_version\": \"media_prompt_understanding.v1\",\n        \"teacher_prompt\": \"Test\",\n        \"language\": \"id\",\n        \"teacher_intent\": {\n            \"type\": \"generate_learning_media\",\n            \"goal\": \"\",\n            \"preferred_delivery_mode\": \"digital_download\",\n            \"requires_clarification\": false\n        },\n        \"learning_objectives\": [],\n        \"constraints\": {},\n        \"output_type_candidates\": [\n            {\"type\": \"pdf\", \"score\": 0.5, \"reason\": \"Reason\"}\n        ],\n        \"resolved_output_type_reasoning\": \"Reason\",\n        \"document_blueprint\": {\n            \"title\": \"T\",\n            \"summary\": \"S\",\n            \"sections\": [{\"title\": \"S\", \"purpose\": \"P\", \"bullets\": [], \"estimated_length\": \"short\"}]\n        },\n        \"teacher_delivery_summary\": \"Summary\",\n        \"confidence\": {\"score\": 0.5, \"label\": \"medium\"}\n    }\"#;\n    let result = prompt_interpretation::decode_and_validate(json);\n    assert!(result.is_err());\n    let err = result.unwrap_err();\n    assert_eq!(err.code, \"provider_response_contract_invalid\");\n}\n\n#[test]\nfn test_interpretation_fallback_creates_valid_response() {\n    let payload = prompt_interpretation::fallback(\"Buatkan materi tentang pecahan\");\n    assert_eq!(payload.schema_version, \"media_prompt_understanding.v1\");\n    assert!(payload.fallback.triggered);\n    assert_eq!(payload.output_type_candidates.len(), 3);\n    assert_eq!(payload.language, \"id\");\n    assert!(payload.teacher_prompt.contains(\"pecahan\"));\n}\n\n#[test]\nfn test_interpretation_fallback_english_prompt() {\n    let payload = prompt_interpretation::fallback(\"Create a worksheet about fractions\");\n    assert_eq!(payload.language, \"en\");\n    assert!(payload.fallback.triggered);\n}\n\n#[test]\nfn test_interpretation_fallback_pdf_is_first_candidate() {\n    let payload = prompt_interpretation::fallback(\"test\");\n    assert_eq!(payload.output_type_candidates[0].r#type, \"pdf\");\n}\n\n#[test]\nfn test_interpretation_fallback_can_be_decoded() {\n    let payload = prompt_interpretation::fallback(\"Buatkan modul ajar\");\n    let json = serde_json::to_string(&payload).unwrap();\n    let result = prompt_interpretation::decode_and_validate(&json);\n    assert!(\n        result.is_ok(),\n        \"fallback payload should be valid: {:?}\",\n        result.err()\n    );\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 2. Content Draft Schema\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_content_draft_schema_version() {\n    assert_eq!(content_draft::SCHEMA_VERSION, \"media_content_draft.v1\");\n}\n\n#[test]\nfn test_content_draft_decode_valid() {\n    let json = r#"{\n        \"schema_version\": \"media_content_draft.v1\",\n        \"title\": \"Materi Pecahan\",\n        \"summary\": \"Pengenalan pecahan untuk kelas 5\",\n        \"sections\": [\n            {\n                \"title\": \"Pengertian\",\n                \"purpose\": \"Perkenalan\",\n                \"body_blocks\": [\n                    {\"type\": \"paragraph\", \"content\": \"Pecahan adalah bagian dari keseluruhan\"}\n                ],\n                \"emphasis\": \"medium\"\n            }\n        ],\n        \"teacher_delivery_summary\": \"Ringkasan pengajaran\"\n    }\"#;\n    let result = content_draft::decode_and_validate(json);\n    assert!(result.is_ok(), \"should decode valid draft: {:?}\", result.err());\n\n    let payload = result.unwrap();\n    assert_eq!(payload.title, \"Materi Pecahan\");\n    assert_eq!(payload.sections.len(), 1);\n    assert_eq!(payload.sections[0].body_blocks.len(), 1);\n    assert!(!payload.fallback.triggered);\n}\n\n#[test]\nfn test_content_draft_decode_empty() {\n    let result = content_draft::decode_and_validate(\"\");\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_content_draft_decode_invalid_json() {\n    let result = content_draft::decode_and_validate(\"{bad}\");\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_content_draft_decode_missing_sections() {\n    // Missing required `sections` field\n    let json = r#\"{\n        \"schema_version\": \"media_content_draft.v1\",\n        \"title\": \"T\",\n        \"summary\": \"S\",\n        \"teacher_delivery_summary\": \"D\"\n    }\"#;\n    let result = content_draft::decode_and_validate(json);\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_content_draft_decode_empty_sections() {\n    let json = r#\"{\n        \"schema_version\": \"media_content_draft.v1\",\n        \"title\": \"T\",\n        \"summary\": \"S\",\n        \"sections\": [],\n        \"teacher_delivery_summary\": \"D\"\n    }\"#;\n    let result = content_draft::decode_and_validate(json);\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_content_draft_fallback_from_interpretation() {\n    let payload = content_draft::fallback_from_interpretation(\n        \"Materi Pecahan\",\n        \"Pengenalan pecahan untuk kelas 5\",\n        \"Gunakan contoh sehari-hari\",\n    );\n    assert_eq!(payload.schema_version, \"media_content_draft.v1\");\n    assert!(payload.fallback.triggered);\n    assert_eq!(payload.sections.len(), 1);\n    assert_eq!(payload.sections[0].body_blocks[0].r#type, \"paragraph\");\n    assert_eq!(payload.title, \"Materi Pecahan\");\n}\n\n#[test]\nfn test_content_draft_fallback_can_be_decoded() {\n    let payload = content_draft::fallback_from_interpretation(\n        \"A\",\n        \"B\",\n        \"C\",\n    );\n    let json = serde_json::to_string(&payload).unwrap();\n    let result = content_draft::decode_and_validate(&json);\n    assert!(result.is_ok(), \"fallback should be valid: {:?}\", result.err());\n}\n\n#[test]\nfn test_content_draft_fallback_truncates_long_titles() {\n    let long = \"a\".repeat(500);\n    let payload = content_draft::fallback_from_interpretation(&long, \"S\", \"D\");\n    assert!(payload.title.len() <= 200);\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 3. Delivery Response Schema\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_delivery_schema_version() {\n    assert_eq!(delivery::SCHEMA_VERSION, \"media_delivery_response.v1\");\n}\n\n#[test]\nfn test_delivery_decode_valid() {\n    let json = r#"{\n        \"schema_version\": \"media_delivery_response.v1\",\n        \"title\": \"Materi Pecahan\",\n        \"preview_summary\": \"PDF materi pecahan kelas 5\",\n        \"teacher_message\": \"Silakan unduh materi di bawah ini\",\n        \"artifact\": {\n            \"output_type\": \"pdf\",\n            \"title\": \"Materi Pecahan\",\n            \"file_url\": \"https://storage.example.com/materi.pdf\",\n            \"mime_type\": \"application/pdf\"\n        },\n        \"publication\": {},\n        \"response_meta\": {\n            \"generated_at\": \"2026-07-14T10:00:00Z\",\n            \"llm_used\": true,\n            \"provider\": \"gemini\",\n            \"model\": \"gemini-2.5-flash-lite\"\n        }\n    }\"#;\n    let result = delivery::decode_and_validate(json);\n    assert!(result.is_ok(), \"should decode valid delivery: {:?}\", result.err());\n\n    let payload = result.unwrap();\n    assert_eq!(payload.artifact.output_type, \"pdf\");\n    assert!(payload.response_meta.llm_used);\n    assert_eq!(\n        payload.response_meta.provider.as_deref(),\n        Some(\"gemini\")\n    );\n}\n\n#[test]\nfn test_delivery_decode_empty() {\n    let result = delivery::decode_and_validate(\"\");\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_delivery_decode_invalid_json() {\n    let result = delivery::decode_and_validate(\"{bad}\");\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_delivery_decode_missing_artifact() {\n    let json = r#"{\n        \"schema_version\": \"media_delivery_response.v1\",\n        \"title\": \"T\",\n        \"preview_summary\": \"S\",\n        \"teacher_message\": \"M\",\n        \"publication\": {},\n        \"response_meta\": {\n            \"generated_at\": \"2026-07-14T10:00:00Z\",\n            \"llm_used\": false\n        }\n    }\"#;\n    let result = delivery::decode_and_validate(json);\n    assert!(result.is_err());\n}\n\n#[test]\nfn test_delivery_decode_missing_file_url_in_artifact() {\n    // Artifact missing required file_url\n    let json = r#"{\n        \"schema_version\": \"media_delivery_response.v1\",\n        \"title\": \"T\",\n        \"preview_summary\": \"S\",\n        \"teacher_message\": \"M\",\n        \"artifact\": {\n            \"output_type\": \"pdf\",\n            \"title\": \"T\",\n            \"file_url\": \"\",\n            \"mime_type\": \"application/pdf\"\n        },\n        \"publication\": {},\n        \"response_meta\": {\n            \"generated_at\": \"2026-07-14T10:00:00Z\",\n            \"llm_used\": false\n        }\n    }\"#;\n    let result = delivery::decode_and_validate(json);\n    assert!(result.is_err());\n    let err = result.unwrap_err();\n    assert_eq!(err.code, \"provider_response_contract_invalid\");\n}\n\n#[test]\nfn test_delivery_fallback_creates_valid_response() {\n    let payload = delivery::fallback(\n        \"Materi Pecahan\",\n        \"PDF materi pecahan kelas 5 SD\",\n        \"pdf\",\n        \"https://storage.example.com/materi.pdf\",\n        \"application/pdf\",\n    );\n    assert_eq!(payload.schema_version, \"media_delivery_response.v1\");\n    assert!(payload.fallback.triggered);\n    assert!(!payload.response_meta.llm_used);\n    assert_eq!(payload.artifact.output_type, \"pdf\");\n    assert!(payload.teacher_message.contains(\"pdf\"));\n}\n\n#[test]\nfn test_delivery_fallback_can_be_decoded() {\n    let payload = delivery::fallback(\"T\", \"S\", \"pdf\", \"https://example.com/f.pdf\", \"application/pdf\");\n    let json = serde_json::to_string(&payload).unwrap();\n    let result = delivery::decode_and_validate(&json);\n    assert!(result.is_ok(), \"fallback should be valid: {:?}\", result.err());\n}\n\n#[test]\nfn test_delivery_fallback_artifact_has_empty_publication() {\n    let payload = delivery::fallback(\"T\", \"S\", \"docx\", \"https://example.com/f.docx\", \"application/docx\");\n    assert!(payload.publication.topic.is_none());\n    assert!(payload.publication.content.is_none());\n    assert!(payload.publication.recommended_project.is_none());\n}\n\n#[test]\nfn test_delivery_fallback_includes_generated_at() {\n    let payload = delivery::fallback(\"T\", \"S\", \"pdf\", \"https://example.com/f.pdf\", \"application/pdf\");\n    assert!(!payload.response_meta.generated_at.is_empty());\n    // Should be an RFC3339 timestamp\n    assert!(\n        payload.response_meta.generated_at.contains('T'),\n        \"expected RFC3339 timestamp\"\n    );\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 4. Cross-schema consistency\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_interpretation_fallback_is_not_delivery() {\n    let payload = prompt_interpretation::fallback(\"test\");\n    // Ensure we don't accidentally mix schemas\n    assert_eq!(payload.schema_version, \"media_prompt_understanding.v1\");\n    assert!(\n        serde_json::to_value(&payload).unwrap().get(\"teacher_intent\").is_some(),\n        \"interpretation payload should have teacher_intent\"\n    );\n}\n\n#[test]\nfn test_delivery_fallback_is_not_draft() {\n    let payload = delivery::fallback(\"T\", \"S\", \"pdf\", \"https://f.com/f.pdf\", \"application/pdf\");\n    assert_eq!(payload.schema_version, \"media_delivery_response.v1\");\n    // Delivery has artifact, draft does not\n    assert!(\n        serde_json::to_value(&payload).unwrap().get(\"artifact\").is_some(),\n        \"delivery payload should have artifact\"\n    );\n}\n\n#[test]\nfn test_all_schema_versions_distinct() {\n    let versions = vec![\n        prompt_interpretation::SCHEMA_VERSION,\n        content_draft::SCHEMA_VERSION,\n        delivery::SCHEMA_VERSION,\n    ];\n    let mut sorted = versions.clone();\n    sorted.sort();\n    sorted.dedup();\n    assert_eq!(versions.len(), sorted.len(), \"all schema versions must be unique\");\n}\n